<section class="combat-stage{{ $background['transparent'] ? ' combat-stage--transparent' : '' }}" id="combat-stage" aria-label="Escenario de combate" @if($background['url']) style="background-image:url('{{ $background['url'] }}')" @endif><div class="combat-stage__participants" id="combat-participants"><div class="combatant combatant--player" data-participant-id="character:{{ $character->id }}"><div class="combatant__visual"><x-character.appearance :appearance="$appearance" :name="$character->name" /></div><strong>{{ $character->name }}</strong><div class="combatant__health-text">{{ $stats['current_health'] }} / {{ $stats['max_health'] }}</div><div class="progress combatant__health" role="progressbar" aria-label="Vida de {{ $character->name }}" aria-valuemin="0" aria-valuemax="{{ $stats['max_health'] }}" aria-valuenow="{{ $stats['current_health'] }}"><div class="progress-bar bg-success" style="width:{{ max(0,min(100,$stats['max_health']>0?$stats['current_health']*100/$stats['max_health']:0)) }}%"></div></div></div></div></section>
